func TestGettersUsrAccess(t *testing.T) {
	t.Run("GetRoleLabel", func(t *testing.T) {
		t.Parallel()
		// Arrange
		obj := &UsrAccess{}
		var expected *string
		obj.RoleLabel = expected

		// Act & Assert
		assert.Equal(t, expected, obj.GetRoleLabel(), "getter should return the property value")
	})

	t.Run("GetRoleLabel_NilValue", func(t *testing.T) {
		t.Parallel()
		// Arrange
		obj := &UsrAccess{}
		obj.RoleLabel = nil

		// Act & Assert
		assert.Nil(t, obj.GetRoleLabel(), "getter should return nil when property is nil")
	})

	t.Run("GetRoleLabel_NilReceiver", func(t *testing.T) {
		t.Parallel()
		var obj *UsrAccess
		// Should not panic - getters should handle nil receiver gracefully
		defer func() {
			if r := recover(); r != nil {
				t.Errorf("Getter panicked on nil receiver: %v", r)
			}
		}()
		_ = obj.GetRoleLabel() // Should return zero value
	})

	t.Run("GetRoleValue", func(t *testing.T) {
		t.Parallel()
		// Arrange
		obj := &UsrAccess{}
		var expected *bool
		obj.RoleValue = expected

		// Act & Assert
		assert.Equal(t, expected, obj.GetRoleValue(), "getter should return the property value")
	})

	t.Run("GetRoleValue_NilValue", func(t *testing.T) {
		t.Parallel()
		// Arrange
		obj := &UsrAccess{}
		obj.RoleValue = nil

		// Act & Assert
		assert.Nil(t, obj.GetRoleValue(), "getter should return nil when property is nil")
	})

	t.Run("GetRoleValue_NilReceiver", func(t *testing.T) {
		t.Parallel()
		var obj *UsrAccess
		// Should not panic - getters should handle nil receiver gracefully
		defer func() {
			if r := recover(); r != nil {
				t.Errorf("Getter panicked on nil receiver: %v", r)
			}
		}()
		_ = obj.GetRoleValue() // Should return zero value
	})

}

