func TestEnumAchHolderType(t *testing.T) {
	t.Run("NewFromString_personal", func(t *testing.T) {
		t.Parallel()
		val, err := NewAchHolderTypeFromString("personal")
		assert.NoError(t, err, "valid enum value should not return error")
		assert.Equal(t, AchHolderType("personal"), val, "enum value should match expected wire value")
	})

	t.Run("NewFromString_business", func(t *testing.T) {
		t.Parallel()
		val, err := NewAchHolderTypeFromString("business")
		assert.NoError(t, err, "valid enum value should not return error")
		assert.Equal(t, AchHolderType("business"), val, "enum value should match expected wire value")
	})

	t.Run("NewFromString_Invalid", func(t *testing.T) {
		_, err := NewAchHolderTypeFromString("invalid_value_that_does_not_exist")
		assert.Error(t, err)
	})

	t.Run("Ptr", func(t *testing.T) {
		val, err := NewAchHolderTypeFromString("personal")
		assert.NoError(t, err)
		ptr := val.Ptr()
		assert.NotNil(t, ptr)
		assert.Equal(t, val, *ptr)
	})
}

